const output = [];
const now = new Date(); // 현재 시간 (워크플로우 실행 시점)

// 현재 달의 주차를 계산하는 함수 (월요일 시작 주차)
function getWeekOfMonth(date) {
    const year = date.getFullYear();
    const month = date.getMonth(); // 0-11
    const firstDayOfMonth = new Date(year, month, 1);
    firstDayOfMonth.setHours(0, 0, 0, 0);

    const firstDayOfThisWeek = new Date(date);
    const dayOfWeek = date.getDay(); // 0: 일, 1: 월 ... 6: 토
    const daysToSubtract = (dayOfWeek === 0) ? 6 : dayOfWeek - 1; // 일요일이면 6일 전 월요일, 아니면 (현재 요일 - 1)일 전 월요일
    firstDayOfThisWeek.setDate(date.getDate() - daysToSubtract);
    firstDayOfThisWeek.setHours(0, 0, 0, 0);

    const diffMs = firstDayOfThisWeek.getTime() - firstDayOfMonth.getTime();
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
    const weekNumber = Math.floor(diffDays / 7) + 1;

    const monthNames = ["1월", "2월", "3월", "4월", "5월", "6월", "7월", "8월", "9월", "10월", "11월", "12월"];
    return `${monthNames[month]} ${weekNumber}`;
}

// 특정 요일의 날짜를 계산하는 함수 (이번 주 내에서)
function getNextWeekdayDateInCurrentWeek(baseDate, weekdayName) {
  const dayMap = {
    '일': 0, '월': 1, '화': 2, '수': 3, '목': 4, '금': 5, '토': 6
  };
  const targetDay = dayMap[weekdayName];
  if (targetDay === undefined) return null;

  const date = new Date(baseDate);
  const currentDay = date.getDay(); // 0: 일, 1: 월...

  let diff = targetDay - currentDay;
  if (diff <= 0) { // 현재 요일이 목표 요일이거나 이미 지난 경우, 다음 주로 넘어가야 함
    diff += 7;
  }
  date.setDate(date.getDate() + diff);
  date.setHours(0, 0, 0, 0); // 시간 초기화

  return date;
}

// 현재 주차 문자열 생성 (매 아이템마다 계산할 필요 없음)
const weekOfMonthText = getWeekOfMonth(now);

// n8n에서 데이터를 가져오는 가장 일반적이고 확실한 방법 (Code 노드에서 권장되는 방식)
for (const item of getItems()) { // <<-- 이 부분이 변경됨! getItems() 함수 사용
  const data = item.json; // <<-- 각 아이템의 JSON 데이터에 접근

  const className = data.name; // 'name' 속성은 최상위에 있다고 가정
  const classDays = Array.isArray(data.property_2) ? data.property_2 : []; // 'property_2'가 요일 배열
  const classTimes = Array.isArray(data.property_1) ? data.property_1 : []; // 'property_1'이 시간 배열
  const studentIds = Array.isArray(data.property_students) ? data.property_students : []; // 'property_students'가 학생 ID 배열

  // 요일이나 시간 정보가 아예 없는 반은 스킵
  if (className && classDays.length > 0 && classTimes.length > 0) {
    let sessionCount = 0;
    for (const day of classDays) {
      for (const time of classTimes) {
        sessionCount++;
        const classDate = getNextWeekdayDateInCurrentWeek(now, day.trim());

        if (classDate) {
          const year = classDate.getFullYear();
          const month = String(classDate.getMonth() + 1).padStart(2, '0');
          const day = String(classDate.getDate()).padStart(2, '0');
          const formattedDate = `${year}-${month}-${day}`;

          const studentsRelation = studentIds.map(id => ({ id: id }));

          output.push({
            className: className,
            studyDate: formattedDate,
            studyTime: time.trim(),
            weekOfMonth: weekOfMonthText,
            sessionNumber: sessionCount,
            studentIdsForNotion: studentsRelation
          });
        }
      }
    }
  } else {
    console.warn(`[SKIP] 반 이름: ${className || data.id} - 요일 또는 시간 정보가 부족합니다.`);
  }
}

return output;
